THOUGHT: The early-exit handling got corrupted. I will ensure the lane extraction is guarded by a proper IsVector declaration and clamp check by rewriting the block to declare IsVector before the condition and then use it in the if, restoring consistent logic. Then I'll submit the patch.

```bash
sed -i '3043,3049c\    auto IsVector = [](ElementCount VF) { return VF.isVector(); };
    if (!IncomingFromEarlyExit->isLiveIn() && LoopVectorizationPlanner::getDecisionAndClampRange(IsVector, Range)) {
      // Update the incoming value from the early exit.
      VPValue *FirstActiveLane = EarlyExitB.createNaryOp(
          VPInstruction::FirstActiveLane, ArrayRef<VPValue *>{CondToEarlyExit}, nullptr,
          "first.active.lane");
      IncomingFromEarlyExit = EarlyExitB.createNaryOp(
          VPInstruction::ExtractLane, ArrayRef<VPValue *>{FirstActiveLane, IncomingFromEarlyExit},
          nullptr, "early.exit.value");
      ExitIRI->setOperand(EarlyExitIdx, IncomingFromEarlyExit);
    }' llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp && submit-patch
```

